UPDATE community_tag
SET tag_uses = tag_uses + 1
WHERE tag_name = #{tagName}

UPDATE community_tag
SET tag_uses = #{tagUses}
WHERE tid = #{tid}

UPDATE community_tag
SET tag_uses = tag_uses-1
WHERE tid = #{tid}

mapper.select:
SELECT tid, tag_name, tag_uses
FROM community_tag
WHERE tag_name = #{tagName}

SELECT t.tag_name,COUNT(r.tag_id) AS tag_count FROM community_tag t join
community_tag_post_relations r on t.tid = #{totalTagId}
GROUP BY t.tid,t.tag_name ORDER BY tag_count DESC  LIMIT 6;

SELECT t.tag_name,COUNT(r.tag_id) AS tag_count FROM community_tag t join
 community_tag_post_relations r on t.tid = r.tag_id

    WHERE r.type=#{type}

GROUP BY t.tid,t.tag_name ORDER BY tag_count DESC  LIMIT 10;

